import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine().trim(); // Trim to remove leading/trailing spaces

        int maxLength = 10; // Maximum length allowed in the buffer
        char[] buffer = new char[maxLength];

        // Copy user input into buffer, ensuring it does not exceed maxLength
        for (int i = 0; i < userInput.length() && i < maxLength; i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("Buffer content: " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
